import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import PlaybookEditor from './components/PlaybookEditor';
import AIAssistant from './components/AIAssistant';
import PrivacyPolicy from './components/PrivacyPolicy';
import TermsOfService from './components/TermsOfService';
import { PLAYBOOK_STRUCTURE } from './constants';
import { UserRole, AppCustomization } from './types';
import { AuthService, supabase, getAppOrigin, SupabaseService } from './services/api';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [selectedModuleId, setSelectedModuleId] = useState<string | null>('dashboard');
  const [currentRole, setCurrentRole] = useState<UserRole>('USER');
  const [loading, setLoading] = useState(true);
  const [appConfig, setAppConfig] = useState<AppCustomization>({
    companyName: 'PhantLab',
    systemLogoUrl: 'http://phant.com.br/uploads/simbolo_roxo.png',
    proposalLogoUrl: 'http://phant.com.br/uploads/logo_light.png',
    primaryColor: '#2563eb'
  });

  // Auth & View States
  const [authView, setAuthView] = useState<'options' | 'email-login' | 'email-signup'>('options');
  const [legalView, setLegalView] = useState<'privacy' | 'terms' | null>(null);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const retryCountRef = useRef(0);

  // Roteamento baseado em URL para links externos (Google OAuth)
  useEffect(() => {
    const handleRouting = () => {
      const params = new URLSearchParams(window.location.search);
      const page = params.get('page');

      if (page === 'privacy') {
        setLegalView('privacy');
      } else if (page === 'terms') {
        setLegalView('terms');
      } else {
        setLegalView(null);
      }
    };

    handleRouting();
    window.addEventListener('popstate', handleRouting);
    return () => window.removeEventListener('popstate', handleRouting);
  }, []);

  const navigateToLegal = (view: 'privacy' | 'terms' | null) => {
    const url = new URL(window.location.href);
    if (view) {
      url.searchParams.set('page', view);
    } else {
      url.searchParams.delete('page');
    }
    window.history.pushState({}, '', url.toString());
    setLegalView(view);
  };

  useEffect(() => {
    // Carregar configuraĂ§Ă”es de marca
    SupabaseService.fetchAppConfig().then(config => {
      if (config) setAppConfig(config);
    });
  }, []);

  useEffect(() => {
    const handleUrlParams = () => {
      const searchParams = new URLSearchParams(window.location.search);
      const hashParams = new URLSearchParams(window.location.hash.substring(1));

      const errorCode = searchParams.get('error') || hashParams.get('error');
      const errorDesc = (searchParams.get('error_description') || hashParams.get('error_description') || "").toLowerCase();

      if (errorCode || errorDesc) {
        let msg = errorDesc || errorCode || "Erro na autenticaĂ§ĂŁo.";
        if (errorDesc.includes('access_denied') || errorCode === '403') {
          msg = "ERRO 403: AMBIENTE DE PREVIEW NĂO AUTORIZADO. O Google exige que esta URL exata esteja cadastrada nos URIs de Redirecionamento.";
        }
        setAuthError(msg);
        window.history.replaceState({}, document.title, window.location.origin + window.location.pathname);
      }
    };

    handleUrlParams();
    window.addEventListener('hashchange', handleUrlParams);
    return () => window.removeEventListener('hashchange', handleUrlParams);
  }, []);

  const loadUserProfile = useCallback(async (userId: string, user: any) => {
    const userEmail = user.email;
    try {
      let profile = await AuthService.getProfile(userId);

      if (!profile && retryCountRef.current < 2) {
        retryCountRef.current++;
        await new Promise(r => setTimeout(r, 1000));
        return loadUserProfile(userId, user);
      }

      if (!profile) {
        profile = {
          id: userId,
          full_name: user.user_metadata?.full_name || user.user_metadata?.picture_name || user.user_metadata?.name || 'Vendedor',
          role: user.user_metadata?.role || 'USER',
          is_fallback: true
        };
      }

      if (userEmail?.toLowerCase() === 'master@phantlab.com.br') {
        profile.role = 'MASTER';
      }

      setUserProfile(profile);
      setCurrentRole(profile.role as UserRole);
      retryCountRef.current = 0;
      return true;
    } catch (err) {
      setUserProfile({ id: userId, role: 'USER', full_name: 'UsuĂĄrio' });
      return false;
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      if (session?.user) {
        setSession(session);
        loadUserProfile(session.user.id, session.user).finally(() => setLoading(false));
      } else {
        setLoading(false);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, newSession) => {
      if (newSession && (event === 'SIGNED_IN' || event === 'INITIAL_SESSION')) {
        setSession(newSession);
        if (!userProfile) {
          setIsProcessing(true);
          await loadUserProfile(newSession.user.id, newSession.user);
          setIsProcessing(false);
        }
      } else if (event === 'SIGNED_OUT') {
        setSession(null);
        setUserProfile(null);
        setCurrentRole('USER');
        setAuthView('options');
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, [loadUserProfile, userProfile]);

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setIsProcessing(true);
    try {
      await AuthService.signInWithEmail(email, password);
    } catch (err: any) {
      setAuthError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
      setIsProcessing(false);
    }
  };

  const handleEmailSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setIsProcessing(true);
    try {
      await AuthService.signUpWithEmail(email, password, fullName);
      alert('Cadastro realizado! Agora vocĂȘ pode fazer login.');
      setAuthView('email-login');
    } catch (err: any) {
      setAuthError(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const copyRedirectUri = () => {
    const uri = `${getAppOrigin()}/`;
    navigator.clipboard.writeText(uri);
    alert("URL Copiada: " + uri);
  };

  if (loading || (session && !userProfile)) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center space-y-6">
          <div className="w-16 h-16 bg-black rounded-[24px] animate-bounce shadow-2xl flex items-center justify-center">
             <div className="w-4 h-4 bg-white rounded-full"></div>
          </div>
          <div className="flex flex-col items-center text-center">
            <span className="text-[11px] font-black text-gray-900 uppercase tracking-[0.4em]">Sincronizando Acesso</span>
          </div>
        </div>
      </div>
    );
  }

  // VisualizaĂ§ĂŁo de PĂĄgina Independente para Termos/Privacidade (Fora do Login ou via URL direta)
  if (legalView) {
    return (
      <div className="min-h-screen bg-gray-50 overflow-y-auto custom-scrollbar animate-in fade-in duration-300">
        <div className="max-w-4xl mx-auto py-20 px-6 relative">
          <button 
            onClick={() => navigateToLegal(null)}
            className="sticky top-0 z-10 mb-12 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-gray-400 hover:text-black transition-colors bg-gray-50/80 backdrop-blur-sm py-4 w-full"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M15 19l-7-7 7-7"/></svg>
            Voltar para o InĂ­cio
          </button>
          {legalView === 'privacy' ? <PrivacyPolicy /> : <TermsOfService />}
        </div>
      </div>
    );
  }

  const AppFooter = () => (
    <footer className="mt-auto pt-12 pb-8 flex flex-col md:flex-row items-center justify-between gap-6 no-print w-full max-w-[1600px] mx-auto px-8 border-t border-gray-100">
      <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest">
        Â© 2024 {appConfig.companyName} Strategic Platform. Todos os direitos reservados.
      </p>
      <div className="flex items-center gap-6">
        <button 
          onClick={() => navigateToLegal('privacy')}
          className="text-[10px] font-black text-gray-300 uppercase tracking-widest hover:text-brand transition-colors"
        >
          Privacidade
        </button>
        <div className="w-1 h-1 rounded-full bg-gray-200"></div>
        <button 
          onClick={() => navigateToLegal('terms')}
          className="text-[10px] font-black text-gray-300 uppercase tracking-widest hover:text-brand transition-colors"
        >
          Termos de Uso
        </button>
      </div>
    </footer>
  );

  const ThemeStyles = () => (
    <style>{`
      :root {
        --brand-primary: ${appConfig.primaryColor};
      }
      .text-brand { color: var(--brand-primary) !important; }
      .bg-brand { background-color: var(--brand-primary) !important; }
      .border-brand { border-color: var(--brand-primary) !important; }
      .text-blue-600, .text-blue-500 { color: var(--brand-primary) !important; }
      .bg-blue-600, .bg-blue-500 { background-color: var(--brand-primary) !important; }
      .bg-blue-50 { background-color: color-mix(in srgb, var(--brand-primary), white 92%) !important; }
    `}</style>
  );

  if (!session) {
    return (
      <div className="min-h-screen w-full flex flex-col bg-gray-50 overflow-y-auto">
        <ThemeStyles />

        <div className="flex-1 flex flex-col items-center justify-center p-6 py-12">
          <div className="max-w-md w-full bg-white p-12 rounded-[60px] shadow-2xl space-y-10 border border-gray-100 text-center animate-in zoom-in-95 duration-500 my-8">
            <div className="w-40 h-40 flex items-center justify-center mx-auto overflow-hidden">
               {appConfig.systemLogoUrl ? (
                 <img src={appConfig.systemLogoUrl} alt="Logo" className="w-full h-full object-contain" />
               ) : (
                 <div className="w-full h-full bg-black rounded-[40px] flex items-center justify-center text-white text-5xl font-black shadow-xl">
                    {appConfig.companyName.charAt(0)}
                 </div>
               )}
            </div>

            <div className="space-y-4">
              <h1 className="text-4xl font-black text-gray-900 tracking-tighter leading-tight">{appConfig.companyName} Playbook</h1>
              <p className="text-gray-400 font-medium text-sm leading-relaxed px-4">
                Acesse sua central de inteligĂȘncia comercial.
              </p>
            </div>

            {authError && (
              <div className="p-8 bg-red-50 text-red-600 text-[11px] font-bold rounded-[32px] border border-red-100 uppercase tracking-widest leading-relaxed animate-in fade-in slide-in-from-top-2 flex flex-col items-center gap-4 text-center">
                <span className="text-2xl">â ïž</span>
                <span className="max-w-[280px]">{authError}</span>
              </div>
            )}

            <div className="space-y-4">
              {authView === 'options' ? (
                <div className="space-y-6">
                  <button 
                    onClick={() => { setAuthError(null); AuthService.signInWithGoogle(); }}
                    className="w-full py-6 bg-white border border-gray-200 text-gray-900 rounded-[30px] font-black text-xs uppercase tracking-[0.2em] shadow-sm hover:bg-gray-50 hover:shadow-lg transition-all flex items-center justify-center gap-3 group"
                  >
                    <svg className="w-5 h-5 group-hover:scale-110 transition-transform" viewBox="0 0 24 24" fill="currentColor">
                      <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                      <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                      <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                      <path d="M12 5.38c1.62 0 3.06.56 4.21 1.66l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
                    </svg>
                    Conectar via Google
                  </button>

                  <div className="flex items-center gap-4 py-2">
                    <div className="flex-1 h-px bg-gray-100"></div>
                    <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Ou</span>
                    <div className="flex-1 h-px bg-gray-100"></div>
                  </div>

                  <button 
                    onClick={() => setAuthView('email-login')}
                    className="w-full py-6 bg-black text-white rounded-[30px] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-gray-800 transition-all flex items-center justify-center gap-3"
                  >
                    Acesso via E-mail e Senha
                  </button>
                </div>
              ) : (
                <form onSubmit={authView === 'email-login' ? handleEmailLogin : handleEmailSignup} className="space-y-4 text-left">
                  {authView === 'email-signup' && (
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">Nome Completo</label>
                      <input 
                        type="text" 
                        required 
                        value={fullName}
                        onChange={(e) => setFullName(e.target.value)}
                        className="w-full px-6 py-4 bg-gray-50 border border-transparent rounded-2xl font-bold text-sm focus:bg-white focus:border-brand outline-none transition-all"
                        placeholder="Seu nome"
                      />
                    </div>
                  )}
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">E-mail</label>
                    <input 
                      type="email" 
                      required 
                      value={email}
                      onChange={(e) => setEmail(e.target.value)}
                      className="w-full px-6 py-4 bg-gray-50 border border-transparent rounded-2xl font-bold text-sm focus:bg-white focus:border-brand outline-none transition-all"
                      placeholder="seu@email.com"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">Senha</label>
                    <input 
                      type="password" 
                      required 
                      value={password}
                      onChange={(e) => setPassword(e.target.value)}
                      className="w-full px-6 py-4 bg-gray-50 border border-transparent rounded-2xl font-bold text-sm focus:bg-white focus:border-brand outline-none transition-all"
                      placeholder="âąâąâąâąâąâąâąâą"
                    />
                  </div>
                  <button 
                    type="submit"
                    disabled={isProcessing}
                    className="w-full py-6 bg-brand text-white rounded-[30px] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-black disabled:opacity-50 transition-all mt-6"
                  >
                    {isProcessing ? 'Carregando...' : authView === 'email-login' ? 'Acessar Playbook' : 'Criar minha Conta'}
                  </button>
                  <button 
                    type="button"
                    onClick={() => { setAuthView('options'); setAuthError(null); }}
                    className="w-full py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-black transition-colors"
                  >
                    Voltar Ă s opĂ§Ă”es
                  </button>
                </form>
              )}
            </div>
          </div>
        </div>

        <AppFooter />
      </div>
    );
  }

  const selectedModule = PLAYBOOK_STRUCTURE.find(m => m.id === selectedModuleId);

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans selection:bg-blue-100 selection:text-blue-900">
      <ThemeStyles />
      <Sidebar 
        modules={PLAYBOOK_STRUCTURE} 
        selectedModuleId={selectedModuleId} 
        onSelectModule={setSelectedModuleId}
        currentRole={currentRole}
        user={{ ...session.user, profile: userProfile }}
        appConfig={appConfig}
      />
      <main className="flex-1 overflow-y-auto relative custom-scrollbar flex flex-col">
        <div className="p-8 md:p-16 max-w-[1600px] mx-auto flex-1 w-full">
          {selectedModule ? (
            <PlaybookEditor 
              module={selectedModule} 
              currentRole={currentRole} 
              onNavigateToModule={setSelectedModuleId}
              appConfig={appConfig}
            />
          ) : (
            <div className="h-full flex items-center justify-center text-gray-300 font-black uppercase tracking-[0.3em]">
              MĂłdulo nĂŁo encontrado
            </div>
          )}
        </div>
        <AppFooter />
      </main>
      <AIAssistant currentRole={currentRole} />
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { PlaybookModule, UserRole, AppCustomization } from '../types';
import { AppIcon } from './Icons';
import { StorageService, AuthService } from '../services/api';

interface SidebarProps {
  modules: PlaybookModule[];
  selectedModuleId: string | null;
  onSelectModule: (id: string | null) => void;
  currentRole: UserRole;
  user?: any;
  appConfig?: AppCustomization;
}

const Sidebar: React.FC<SidebarProps> = ({ modules, selectedModuleId, onSelectModule, currentRole, user, appConfig }) => {
  const [isWorkspaceConnected, setIsWorkspaceConnected] = useState(false);
  const categories = ['SISTEMA', 'BASE', 'PRODUTIZACAO'];

  const filteredModules = modules.filter(m => m.permissions.includes(currentRole));
  const adminModule = filteredModules.find(m => m.id === 'admin');
  const otherModules = filteredModules.filter(m => m.id !== 'admin');

  useEffect(() => {
    const checkConnection = async () => {
      const link = await StorageService.getSavedDriveConfig();
      setIsWorkspaceConnected(!!link);
    };
    checkConnection();
    window.addEventListener('storage', checkConnection);
    return () => window.removeEventListener('storage', checkConnection);
  }, []);

  const profileImage = user?.user_metadata?.avatar_url || 
                       user?.user_metadata?.picture || 
                       `https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.email}`;

  const profileName = user?.user_metadata?.full_name || 
                      user?.user_metadata?.name || 
                      'Vendedor';

  return (
    <div className="w-24 md:w-64 h-full bg-white border-r border-gray-100 flex flex-col transition-all no-print">
      {/* USUĂRIO E LOGO */}
      <div className="p-8 space-y-8">
        <div className="flex items-center space-x-3">
          <div className="w-12 h-12 flex items-center justify-center shrink-0 overflow-hidden">
             {appConfig?.systemLogoUrl ? (
               <img src={appConfig.systemLogoUrl} alt="Logo" className="w-full h-full object-contain" />
             ) : (
               <div className="w-full h-full bg-black rounded-xl flex items-center justify-center text-white font-bold text-xl shadow-lg">
                {appConfig?.companyName.charAt(0) || 'P'}
               </div>
             )}
          </div>
          <div className="hidden md:block overflow-hidden">
            <span className="font-extrabold text-lg tracking-tight text-gray-900 block leading-none truncate">
              {appConfig?.companyName || 'PhantLab'}
            </span>
            <span className="text-[10px] font-bold text-gray-400 mt-1 block uppercase tracking-widest">Interface</span>
          </div>
        </div>

        {user && (
          <div className="hidden md:flex items-center space-x-3 p-3 bg-gray-50 rounded-[20px] border border-gray-100 group relative">
             <div className="w-10 h-10 rounded-xl overflow-hidden border-2 border-white shadow-sm shrink-0">
                <img src={profileImage} alt="User" className="w-full h-full object-cover" />
             </div>
             <div className="overflow-hidden">
                <p className="text-[11px] font-black text-gray-900 truncate leading-none">{profileName}</p>
                <button 
                  onClick={() => AuthService.signOut()}
                  className="text-[9px] font-black text-gray-400 uppercase tracking-widest hover:text-red-500 transition-colors mt-1"
                >
                  Sair do Sistema
                </button>
             </div>
          </div>
        )}
      </div>

      {/* MODULOS DINAMICOS */}
      <div className="flex-1 px-4 overflow-y-auto space-y-8 mt-4 custom-scrollbar">
        {categories.map(cat => {
          const catModules = otherModules.filter(m => m.category === cat);
          if (catModules.length === 0) return null;

          return (
            <div key={cat} className="space-y-1">
              <span className="hidden md:block text-[9px] font-black text-gray-300 uppercase tracking-[0.2em] ml-4 mb-3">
                {cat === 'BASE' ? 'Fundamentos' : cat === 'PRODUTIZACAO' ? 'Ferramentas' : 'Geral'}
              </span>
              {catModules.map(m => (
                <button
                  key={m.id}
                  onClick={() => onSelectModule(m.id)}
                  className={`w-full flex items-center justify-center md:justify-start space-x-3.5 px-4 py-3 rounded-2xl transition-all group ${
                    selectedModuleId === m.id 
                      ? 'bg-black text-white shadow-lg'
                      : 'text-gray-400 hover:bg-gray-50 hover:text-gray-900 hover:text-brand'
                  }`}
                >
                  <AppIcon name={m.icon || 'home'} size={18} className={selectedModuleId === m.id ? '' : 'group-hover:scale-110 transition-transform'} />
                  <span className="hidden md:block font-bold text-[13px]">{m.title}</span>
                </button>
              ))}
            </div>
          );
        })}

        {adminModule && (
          <div className="space-y-1 pt-4 border-t border-gray-50">
            <span className="hidden md:block text-[9px] font-black text-gray-300 uppercase tracking-[0.2em] ml-4 mb-3">
              AdministraĂ§ĂŁo
            </span>
            <button
              onClick={() => onSelectModule(adminModule.id)}
              className={`w-full flex items-center justify-center md:justify-start space-x-3.5 px-4 py-3 rounded-2xl transition-all group ${
                selectedModuleId === adminModule.id 
                  ? 'bg-brand text-white shadow-lg shadow-blue-500/20'
                  : 'text-gray-400 hover:bg-gray-50 hover:text-gray-900 hover:text-brand'
              }`}
            >
              <AppIcon name={adminModule.icon || 'settings'} size={18} className={selectedModuleId === adminModule.id ? '' : 'group-hover:scale-110 transition-transform'} />
              <span className="hidden md:block font-bold text-[13px]">{adminModule.title}</span>
            </button>
          </div>
        )}
      </div>

      {/* FOOTER - STATUS DA CONEXĂO */}
      <div className="p-4 border-t border-gray-50 mt-auto">
        <div className={`flex items-center justify-between p-3 rounded-2xl border ${isWorkspaceConnected ? 'bg-green-50/30 border-green-100' : 'bg-gray-50 border-gray-100'}`}>
           <div className="flex items-center space-x-2">
              <div className="flex -space-x-1">
                 <div className="w-1.5 h-1.5 rounded-full bg-[#4285F4]"></div>
                 <div className="w-1.5 h-1.5 rounded-full bg-[#EA4335]"></div>
                 <div className="w-1.5 h-1.5 rounded-full bg-[#FBBC05]"></div>
                 <div className="w-1.5 h-1.5 rounded-full bg-[#34A853]"></div>
              </div>
              <span className="hidden md:block text-[9px] font-black text-gray-500 uppercase tracking-widest">Workspace</span>
           </div>
           <span className={`w-2 h-2 rounded-full ${isWorkspaceConnected ? 'bg-green-500 animate-pulse' : 'bg-gray-300'}`}></span>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect, useRef } from 'react';
import { ProposalItem, StrategicMapItem, ProposalMetadata, SolutionItem, ProposalRecord, AppCustomization } from '../types';
import { generateStrategicMapping, improveObservationText } from '../services/gemini';
import { SupabaseService } from '../services/api';
import ProposalPresentation from './ProposalPresentation';

interface ProposalBuilderProps {
  appConfig: AppCustomization;
}

const PhantPattern = () => (
  <svg width="100%" height="100%" className="absolute inset-0 pointer-events-none opacity-[0.03]">
    <pattern id="phant-text" x="0" y="0" width="200" height="100" patternUnits="userSpaceOnUse">
      <text x="10" y="60" fontFamily="Inter" fontWeight="900" fontSize="40" fill="currentColor">PHANT</text>
    </pattern>
    <rect width="100%" height="100%" fill="url(#phant-text)" />
  </svg>
);

const ProposalBuilder: React.FC<ProposalBuilderProps> = ({ appConfig }) => {
  const [proposalItems, setProposalItems] = useState<ProposalItem[]>([]);
  const [strategicMap, setStrategicMap] = useState<StrategicMapItem[]>([]);
  const [catalog, setCatalog] = useState<SolutionItem[]>([]);
  const [proposalHistory, setProposalHistory] = useState<ProposalRecord[]>([]);
  const [metadata, setMetadata] = useState<ProposalMetadata>({
    clientName: '',
    industry: '',
    website: '',
    instagram: '',
    meetingNotesPains: '',
    meetingNotesDesires: '',
    observations: '',
    date: new Date().toLocaleDateString('pt-BR'),
    consultant: 'Estrategista PhantLab',
    headline: 'PROPOSTA DE MOVIMENTO ESTRATĂGICO'
  });

  const [isGeneratingAI, setIsGeneratingAI] = useState(false);
  const [isImprovingText, setIsImprovingText] = useState(false);
  const [exportStatus, setExportStatus] = useState<'idle' | 'saving' | 'ready' | 'error'>('idle');
  const [activeTab, setActiveTab] = useState<'info' | 'solutions' | 'mapping' | 'history'>('info');
  const [zoom, setZoom] = useState(0.45);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [showPresentation, setShowPresentation] = useState(false);
  const [validationError, setValidationError] = useState<string | null>(null);
  const previewRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const saved = localStorage.getItem('phant_current_proposal');
    if (saved) setProposalItems(JSON.parse(saved));
    SupabaseService.fetchSolutions().then(data => setCatalog(data || []));
    loadHistory();
  }, []);

  const loadHistory = async () => {
    const history = await SupabaseService.fetchProposalsHistory();
    setProposalHistory(history || []);
  };

  const total = proposalItems.reduce((acc, curr) => acc + curr.totalPrice, 0);
  const formatCurrency = (val: number) => 
    new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val);

  const handleGenerateAI = async () => {
    if (!metadata.clientName) {
      setValidationError("O nome do cliente Ă© obrigatĂłrio para anĂĄlise.");
      setActiveTab('info');
      setTimeout(() => setValidationError(null), 3000);
      return;
    }
    setIsGeneratingAI(true);
    try {
      const mapping = await generateStrategicMapping(metadata);
      setStrategicMap(mapping || []);
      setActiveTab('mapping');
    } catch (err) {
      console.error(err);
      setValidationError("A pesquisa da IA falhou.");
    } finally {
      setIsGeneratingAI(false);
    }
  };

  const handleImproveText = async () => {
    if (!metadata.observations?.trim() || isImprovingText) return;
    setIsImprovingText(true);
    try {
      const improved = await improveObservationText(metadata.observations);
      setMetadata(prev => ({ ...prev, observations: improved }));
    } finally {
      setIsImprovingText(false);
    }
  };

  const handleAddSolution = (sol: SolutionItem) => {
    const newItem: ProposalItem = {
      instanceId: `manual-${Date.now()}`,
      solutionId: sol.id,
      name: sol.solucao,
      basePrice: sol.valor_base_num,
      selectedOptions: [],
      totalPrice: sol.valor_base_num,
      duration: sol.duracao,
      description: sol.descricao,
      deliverables: sol.entregaveis || []
    };
    setProposalItems(prev => [...prev, newItem]);
  };

  const removeSolution = (id: string) => {
    setProposalItems(prev => prev.filter(p => p.instanceId !== id));
  };

  const handlePrint = () => {
    // Adiciona classe de impressĂŁo ao body
    document.body.classList.add("is-printing");

    // Pequeno delay para garantir que o CSS media print seja interpretado
    setTimeout(() => {
      window.print();
      // Remove apĂłs o fechamento da caixa de diĂĄlogo de impressĂŁo
      setTimeout(() => {
        document.body.classList.remove("is-printing");
      }, 500);
    }, 100);
  };

  const handleExport = async () => {
    if (!metadata.clientName) {
      setValidationError("Defina o nome do cliente antes de salvar.");
      setActiveTab('info');
      setTimeout(() => setValidationError(null), 3000);
      return;
    }
    if (exportStatus !== 'idle') return;

    setExportStatus('saving');
    try {
      const res = await SupabaseService.saveProposal(
        metadata.clientName,
        metadata.industry || "N/A",
        total,
        metadata.consultant,
        proposalItems,
        metadata
      );

      if (!res.success) {
        throw new Error(res.message);
      }

      await loadHistory();
      setExportStatus('ready');

      setTimeout(() => {
        handlePrint();
        setExportStatus('idle');
      }, 1000);

    } catch (err: any) {
      console.error("Erro na exportaĂ§ĂŁo:", err);
      setExportStatus('error');
      setTimeout(() => setExportStatus('idle'), 4000);
    }
  };

  const loadFromHistory = (record: ProposalRecord) => {
    if (!record) return;
    setProposalItems(Array.isArray(record.items) ? record.items : []);
    setMetadata({
      clientName: record.client_name || '',
      industry: record.industry || '',
      website: record.metadata?.website || '',
      instagram: record.metadata?.instagram || '',
      meetingNotesPains: record.metadata?.meetingNotesPains || '',
      meetingNotesDesires: record.metadata?.meetingNotesDesires || '',
      observations: record.metadata?.observations || '',
      date: record.metadata?.date || new Date(record.created_at).toLocaleDateString('pt-BR'),
      consultant: record.consultant || 'Estrategista PhantLab',
      headline: record.metadata?.headline || 'PROPOSTA DE MOVIMENTO ESTRATĂGICO'
    });
    setActiveTab('solutions');
    const scrollArea = document.querySelector('.proposal-preview-area');
    if (scrollArea) scrollArea.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const adjustZoom = (delta: number) => setZoom(prev => Math.min(Math.max(prev + delta, 0.2), 2));
  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      previewRef.current?.requestFullscreen();
      setIsFullscreen(true);
    } else {
      document.exitFullscreen();
      setIsFullscreen(false);
    }
  };

  return (
    <div className={`flex flex-col lg:flex-row gap-8 animate-in fade-in duration-700 ${isFullscreen ? 'fixed inset-0 z-[100] bg-[#1a1a1a] p-0 overflow-hidden' : ''}`}>

      {showPresentation && (
        <ProposalPresentation 
          metadata={metadata} 
          items={proposalItems} 
          strategicMap={strategicMap} 
          appConfig={appConfig}
          onClose={() => setShowPresentation(false)}
        />
      )}

      {!isFullscreen && (
        <div className="w-full lg:w-[450px] space-y-8 no-print shrink-0">
          <header className="space-y-2">
            <h2 className="text-4xl font-black text-gray-900 tracking-tighter">Gerador Proposta.</h2>
            <p className="text-gray-400 text-sm font-medium">Configure os dados antes de exportar o PDF.</p>
          </header>

          <div className="bg-white rounded-[40px] border border-gray-100 shadow-xl overflow-hidden flex flex-col h-[750px] relative">
            {validationError && (
              <div className="absolute top-16 left-0 right-0 z-50 px-8 py-3 bg-red-600 text-white text-[10px] font-black uppercase tracking-widest text-center animate-in slide-in-from-top-full duration-300">
                {validationError}
              </div>
            )}

            <nav className="flex p-4 gap-2 bg-gray-50 border-b border-gray-100 no-print">
              {(['info', 'solutions', 'mapping', 'history'] as const).map(t => (
                <button 
                  key={t}
                  onClick={() => setActiveTab(t)}
                  className={`flex-1 py-3 rounded-2xl text-[9px] font-black uppercase tracking-widest transition-all ${activeTab === t ? 'bg-black text-white shadow-lg' : 'text-gray-400 hover:text-black'}`}
                >
                  {t === 'info' ? 'Dados' : t === 'solutions' ? 'Itens' : t === 'mapping' ? 'EstratĂ©gia' : 'Salvas'}
                </button>
              ))}
            </nav>

            <div className="flex-1 overflow-y-auto p-8 space-y-8 custom-scrollbar no-print">
              {activeTab === 'info' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                  <div className="space-y-2">
                    <label className={`text-[10px] font-black uppercase tracking-widest ml-2 transition-colors ${validationError ? 'text-red-500' : 'text-gray-300'}`}>Nome do Cliente</label>
                    <input 
                      value={metadata.clientName}
                      onChange={e => {
                        setMetadata({...metadata, clientName: e.target.value.toUpperCase()});
                        if (validationError) setValidationError(null);
                      }}
                      className="w-full bg-gray-50 border-transparent border focus:border-brand p-4 rounded-2xl font-black text-sm outline-none transition-all"
                      placeholder="CLIENTE EXEMPLO"
                    />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-2">Website</label>
                      <input 
                        value={metadata.website}
                        onChange={e => setMetadata({...metadata, website: e.target.value})}
                        className="w-full bg-gray-50 p-4 rounded-2xl font-bold text-xs outline-none"
                        placeholder="site.com.br"
                      />
                    </div>
                    <div className="space-y-2">
                      <label className="text-[10px] font-black text-gray-300 uppercase tracking-widest ml-2">Instagram</label>
                      <input 
                        value={metadata.instagram}
                        onChange={e => setMetadata({...metadata, instagram: e.target.value})}
                        className="w-full bg-gray-50 p-4 rounded-2xl font-bold text-xs outline-none"
                        placeholder="@perfil"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-amber-500 uppercase tracking-widest ml-2">Dores do Cliente</label>
                    <textarea 
                      value={metadata.meetingNotesPains}
                      onChange={e => setMetadata({...metadata, meetingNotesPains: e.target.value})}
                      className="w-full bg-gray-50 p-4 rounded-2xl font-medium text-xs min-h-[80px] outline-none"
                      placeholder="Quais problemas ele tem hoje?"
                    />
                  </div>

                  <button 
                    onClick={handleGenerateAI}
                    disabled={isGeneratingAI}
                    className="w-full py-5 bg-brand text-white rounded-[30px] font-black text-[10px] uppercase tracking-widest hover:bg-black transition-all shadow-xl disabled:opacity-50"
                  >
                    {isGeneratingAI ? 'ANALISANDO WEB...' : 'âš Analisar Empresa com IA'}
                  </button>
                </div>
              )}

              {activeTab === 'solutions' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                   <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Itens na Proposta</h4>
                   {proposalItems.length > 0 ? proposalItems.map(item => (
                      <div key={item.instanceId} className="p-4 bg-gray-50 rounded-2xl flex justify-between items-center group">
                        <div className="overflow-hidden">
                          <p className="font-black text-[11px] truncate">{item.name}</p>
                          <p className="text-[9px] text-brand font-bold uppercase">{formatCurrency(item.totalPrice)}</p>
                        </div>
                        <button onClick={() => removeSolution(item.instanceId)} className="text-gray-300 hover:text-red-500 transition-all">
                          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M6 18L18 6M6 6l12 12"/></svg>
                        </button>
                      </div>
                    )) : (
                      <p className="text-center py-10 text-[10px] font-black text-gray-300 uppercase">Nenhum item selecionado.</p>
                    )}

                    <div className="pt-6 border-t border-gray-100 space-y-4">
                      <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">CatĂĄlogo</h4>
                      <div className="grid grid-cols-1 gap-2">
                        {catalog.map(sol => (
                          <button 
                            key={sol.id}
                            onClick={() => handleAddSolution(sol)}
                            className="w-full text-left p-4 bg-white border border-gray-100 rounded-2xl hover:border-brand transition-all flex justify-between items-center group"
                          >
                            <span className="font-bold text-[11px] text-gray-600 group-hover:text-black">{sol.solucao}</span>
                            <span className="text-[8px] font-black text-brand tracking-widest">+ ADD</span>
                          </button>
                        ))}
                      </div>
                    </div>
                </div>
              )}

              {activeTab === 'mapping' && (
                <div className="space-y-6 animate-in slide-in-from-left-4 duration-300">
                   <h4 className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Mapa IA de Movimento</h4>
                   {strategicMap.map((m, i) => (
                    <div key={i} className="p-6 bg-gray-50 rounded-[24px] border border-gray-100 space-y-4">
                        <textarea 
                          value={m.current}
                          onChange={e => {
                            const next = [...strategicMap];
                            next[i].current = e.target.value;
                            setStrategicMap(next);
                          }}
                          className="w-full bg-transparent border-none p-0 text-[10px] font-medium text-gray-400 resize-none focus:ring-0"
                          placeholder="Estado Atual"
                        />
                        <div className="h-px bg-gray-200 w-full"></div>
                        <textarea 
                          value={m.desired}
                          onChange={e => {
                            const next = [...strategicMap];
                            next[i].desired = e.target.value;
                            setStrategicMap(next);
                          }}
                          className="w-full bg-transparent border-none p-0 text-xs font-black text-gray-900 resize-none focus:ring-0"
                          placeholder="Estado Desejado"
                        />
                    </div>
                  ))}
                </div>
              )}

              {activeTab === 'history' && (
                <div className="space-y-4 animate-in slide-in-from-left-4 duration-300">
                  {proposalHistory.map(record => (
                    <div key={record.id} className="p-5 bg-gray-50 rounded-[24px] border border-gray-100 group hover:border-brand transition-all cursor-pointer" onClick={() => loadFromHistory(record)}>
                       <p className="font-black text-[12px] text-gray-900 leading-none">{record.client_name}</p>
                       <div className="flex justify-between items-center mt-3">
                          <span className="text-[8px] font-bold text-gray-400 uppercase tracking-widest">{new Date(record.created_at).toLocaleDateString('pt-BR')}</span>
                          <span className="text-[10px] font-black text-brand">{formatCurrency(record.total_value)}</span>
                       </div>
                    </div>
                  ))}
                </div>
              )}
            </div>

            <div className="p-8 bg-black text-white space-y-4 no-print">
              <div className="space-y-2">
                 <div className="flex justify-between items-center">
                    <label className="text-[9px] font-black text-white/40 uppercase tracking-widest">ObservaĂ§Ă”es extras</label>
                    <button onClick={handleImproveText} className="text-[8px] font-black text-brand uppercase tracking-widest">âš Refinar Texto</button>
                 </div>
                 <textarea 
                  value={metadata.observations}
                  onChange={e => setMetadata({...metadata, observations: e.target.value})}
                  className="w-full bg-white/5 border border-white/10 p-4 rounded-xl text-[10px] font-medium text-white/80 min-h-[60px] outline-none focus:bg-white/10"
                  placeholder="Acordos de pagamento..."
                 />
              </div>

              <div className="flex justify-between items-end">
                  <span className="text-[10px] font-black text-white/30 uppercase tracking-widest">Valor Final</span>
                  <span className="text-3xl font-black tracking-tighter">{formatCurrency(total)}</span>
              </div>

              <div className="grid grid-cols-1 gap-2">
                <button 
                  onClick={handleExport} 
                  disabled={exportStatus !== 'idle'}
                  className="w-full py-4 bg-emerald-600 text-white rounded-[24px] font-black text-[11px] uppercase tracking-[0.2em] shadow-xl hover:scale-105 transition-all disabled:opacity-50 flex items-center justify-center gap-3"
                >
                  {exportStatus === 'saving' ? 'SALVANDO...' : 
                   exportStatus === 'ready' ? 'SUCESSO! IMPRIMINDO...' : 
                   'SALVAR E GERAR PDF'}
                </button>
                <button 
                  onClick={() => setShowPresentation(true)}
                  className="w-full py-4 bg-[#6113cc] text-white rounded-[24px] font-black text-[11px] uppercase tracking-[0.2em] shadow-xl hover:scale-105 transition-all flex items-center justify-center gap-3"
                >
                  đ„ïž GERAR APRESENTAĂĂO
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ĂREA DE PREVIEW A4 - O CORAĂĂO DO PLUGIN */}
      <div 
        className={`flex-1 relative flex flex-col items-center bg-[#151515] rounded-[60px] overflow-y-auto custom-scrollbar proposal-preview-area ${isFullscreen ? 'h-full w-full rounded-none' : 'p-12 max-h-[850px]'}`}
      >
        <div className="sticky top-4 z-[50] no-print bg-white/10 backdrop-blur-xl border border-white/10 rounded-full p-2 flex items-center gap-2 mb-8 shadow-2xl">
          <button onClick={() => adjustZoom(-0.05)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M20 12H4" strokeWidth="3" strokeLinecap="round"/></svg>
          </button>
          <span className="text-[10px] font-black text-white/40 uppercase tracking-widest px-2 min-w-[50px] text-center">{Math.round(zoom * 100)}%</span>
          <button onClick={() => adjustZoom(0.05)} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4" strokeWidth="3" strokeLinecap="round"/></svg>
          </button>
          <div className="w-px h-6 bg-white/10 mx-1"></div>
          <button onClick={handlePrint} className="px-6 py-2.5 bg-emerald-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg hover:scale-105 active:scale-95 transition-all flex items-center gap-2">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M17 17h2a2 2 0 002-2v-4a2 2 0 00-2-2H5a2 2 0 00-2 2v4a2 2 0 002 2h2m2 4h6a2 2 0 002-2v-4a2 2 0 00-2-2H9a2 2 0 00-2 2v4a2 2 0 002 2zm8-12V5a2 2 0 00-2-2H9a2 2 0 00-2 2v4h10z"/></svg>
             IMPRIMIR / PDF
          </button>
          <button onClick={toggleFullscreen} className="w-10 h-10 flex items-center justify-center text-white hover:bg-white/10 rounded-full">
             <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 3h6m0 0v6m0-6L14 10M9 3H3m0 0v6m0-6l7 7M15 21h6m0 0v-6m0 6l-7-7M9 21H3m0 0v-6m0 6l7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"/></svg>
          </button>
        </div>

        <div 
          id="proposal-pages-container"
          className="transition-transform duration-300 flex flex-col items-center origin-top print:transform-none proposal-container"
          style={{ transform: `scale(${zoom})` }}
        >
          {/* PĂGINA 1: CAPA */}
          <section className="printable-page w-[210mm] min-h-[297mm] bg-black text-white p-24 flex flex-col justify-between relative shadow-2xl shrink-0 mb-12 print:mb-0 print:shadow-none animate-in zoom-in-95 duration-500 print-break-after">
            <PhantPattern />
            <div className="relative z-10 flex justify-between items-start">
              <div className="w-48 h-auto overflow-hidden flex items-center justify-start text-black font-black">
                 {appConfig.proposalLogoUrl ? (
                   <img src={appConfig.proposalLogoUrl} alt="Logo" className="w-full h-auto object-contain" />
                 ) : (
                   <span className="text-white text-4xl">{appConfig.companyName.charAt(0) || 'P'}</span>
